class Solution:
    def countBeautifulNumbers(self, l: int, r: int) -> int:
        def is_beautiful(n):
            digits = [int(d) for d in str(n)]
            product = 1
            for d in digits:
                product *= d
            summation = sum(digits)
            return product % summation == 0
        count = 0
        for num in range(l, r + 1):
            if is_beautiful(num):
                count += 1
        return count

class Solution:
    def minZeroArray(self, nums: List[int], queries: List[List[int]]) -> int:
        n = len(nums)
        diff = [0] * (n + 1)
        k = 0
        for l, r, val in queries:
            diff[l] += val
            if r + 1 < n:
                diff[r + 1] -= val
            k += 1
            current = 0
            valid = True
            for i in range(n):
                current += diff[i]
                if nums[i] > current:
                    valid = False
                    break
            if valid and all(nums[i] <= current for i in range(n)):
                return k
        return -1

class Solution:
    def closestEqualElement(self, nums: List[int], queries: List[List[int]]) -> List[int]:
        from collections import defaultdict
        import bisect
        pos = defaultdict(list)
        for i, num in enumerate(nums):
            pos[num].append(i)
        res = []
        for i, k in queries:
            num = nums[i]
            idx_list = pos[num]
            idx = bisect.bisect_left(idx_list, k)
            if idx < len(idx_list) and idx_list[idx] == k:
                res.append(k)
            else:
                left = idx_list[idx - 1] if idx > 0 else float('-inf')
                right = idx_list[idx] if idx < len(idx_list) else float('inf')
                if abs(left - k) <= abs(right - k):
                    res.append(left)
                else:
                    res.append(right)
        return res

class Solution:
    def maxUniqueSubarraySum(self, nums: List[int]) -> int:
        seen = set()
        current_sum = max_sum = left = 0
        for right in range(len(nums)):
            while nums[right] in seen:
                seen.remove(nums[left])
                current_sum -= nums[left]
                left += 1
            seen.add(nums[right])
            current_sum += nums[right]
            max_sum = max(max_sum, current_sum)
        return max_sum

class Solution:
    def longestSpecialPath(self, nums: List[int], edges: List[List[int]]) -> List[int]:
        from collections import defaultdict, Counter
        graph = defaultdict(list)
        for u, v in edges:
            graph[u].append(v)
            graph[v].append(u)
        def dfs(node, parent):
            count = Counter()
            max_length = 0
            min_nodes = float('inf')
            for neighbor in graph[node]:
                if neighbor == parent:
                    continue
                length, nodes, sub_count = dfs(neighbor, node)
                if any(sub_count[val] + count[val] > 2 for val in sub_count):
                    continue
                count += sub_count
                if length > max_length or (length == max_length and nodes < min_nodes):
                    max_length = length
                    min_nodes = nodes
            count[nums[node]] += 1
            return max_length + nums[node], min_nodes + 1, count
        max_length, min_nodes, _ = dfs(0, -1)
        return [max_length, min_nodes] if max_length > 0 else [0, 0]

class Solution:
    def longestCommonPrefixAfterRemoval(self, words: List[str], k: int) -> List[int]:
        def common_prefix_length(strs):
            if not strs: return 0
            min_len = min(len(s) for s in strs)
            for i in range(min_len):
                if len(set(s[i] for s in strs)) > 1:
                    return i
            return min_len
        n = len(words)
        answer = [0] * n
        for i in range(n):
            remaining_words = words[:i] + words[i+1:]
            if len(remaining_words) < k:
                answer[i] = 0
            else:
                max_prefix = 0
                for comb in itertools.combinations(remaining_words, k):
                    max_prefix = max(max_prefix, common_prefix_length(comb))
                answer[i] = max_prefix
        return answer

class Spreadsheet:
    def __init__(self):
        self.cells = {}
        self.dependencies = {}

    def set_cell(self, cell: str, value: Union[int, str]) -> None:
        self.cells[cell] = value
        if isinstance(value, str) and value.startswith('='):
            self.dependencies[cell] = self.parse_formula(value[1:])
        else:
            self.dependencies[cell] = []
        self.update_dependents(cell)

    def get_cell(self, cell: str) -> int:
        value = self.cells.get(cell, 0)
        if isinstance(value, int):
            return value
        return self.evaluate_formula(value[1:])

    def parse_formula(self, formula: str) -> List[str]:
        # Parse the formula and return a list of referenced cells
        # This is a simplified parser; a full implementation would handle more cases
        tokens = formula.replace('+', ' ').replace('-', ' ').replace('*', ' ').replace('/', ' ').split()
        return [token for token in tokens if token.isalpha()]

    def evaluate_formula(self, formula: str) -> int:
        # Evaluate the formula by replacing cell references with their values
        for cell in self.parse_formula(formula):
            formula = formula.replace(cell, str(self.get_cell(cell)))
        try:
            return eval(formula)
        except Exception as e:
            raise ValueError(f'Invalid formula: {formula}') from e

    def update_dependents(self, cell: str) -> None:
        # Update all cells that depend on the given cell
        for dependent, refs in self.dependencies.items():
            if cell in refs:
                self.cells[dependent] = '=' + ' '.join(str(self.get_cell(ref)) if ref == cell else ref for ref in refs)

class Solution:
    def findEvenNumbers(self, digits: List[int]) -> List[int]:
        from collections import Counter
        cnt = Counter(digits)
        ans = []
        for x in range(100, 1000, 2):
            cnt1 = Counter(int(d) for d in str(x))
            if all(cnt[d] >= cnt1[d] for d in cnt1):
                ans.append(x)
        return ans

class Solution:
    def maxSubarrays(self, n: int, conflictingPairs: List[List[int]]) -> int:
        from collections import defaultdict
        conflicts = defaultdict(list)
        for a, b in conflictingPairs:
            conflicts[max(a, b)].append(min(a, b))
        valid_subarrays = 0
        max_left = 0
        second_max_left = 0
        gains = [0] * (n + 1)
        for right in range(1, n + 1):
            for left in conflicts[right]:
                if left > max_left:
                    second_max_left = max_left
                    max_left = left
                elif left > second_max_left:
                    second_max_left = left
            valid_subarrays += right - max_left
            gains[max_left] += max_left - second_max_left
        return valid_subarrays + max(gains)

class Solution:
    def numOfUnplacedFruits(self, fruits: List[int], baskets: List[int]) -> int:
        fruits.sort()
        baskets.sort()
        i = j = 0
        while i < len(fruits) and j < len(baskets):
            if fruits[i] <= baskets[j]:
                i += 1
            j += 1
        return len(fruits) - i

