class Solution:
    def mergeStrings(self, str1: str, str2: str) -> str:
        i, j = 0, 0
        result = []
        while i < len(str1) and j < len(str2):
            if str1[i] < str2[j]:
                result.append(str1[i])
                i += 1
            else:
                result.append(str2[j])
                j += 1
        result.extend(str1[i:])
        result.extend(str2[j:])
        return ''.join(result)

class Solution:
    def maxSum(self, nums: List[int], k: int, m: int) -> int:
        from itertools import accumulate
        from functools import lru_cache
        n = len(nums)
        prefix = [0] + list(accumulate(nums))
        @lru_cache(None)
        def dp(i, k):
            if k == 0:
                return 0
            if i + m > n:
                return float('-inf')
            return max(dp(j, k - 1) + prefix[j] - prefix[i] for j in range(i + m, n + 1))
        return dp(0, k)

class Solution:
    def longestPalindromeSubseq(self, s: str, k: int) -> int:
        n = len(s)
        dp = [[0] * n for _ in range(n)]
        for i in range(n):
            dp[i][i] = 1
        for length in range(2, n + 1):
            for i in range(n - length + 1):
                j = i + length - 1
                if s[i] == s[j]:
                    dp[i][j] = dp[i + 1][j - 1] + 2
                else:
                    dp[i][j] = max(dp[i + 1][j], dp[i][j - 1])
        for length in range(n, 0, -1):
            for i in range(n - length + 1):
                j = i + length - 1
                if length - dp[i][j] <= k:
                    return length
        return 0

class Solution:
    def findLargestAlmostMissing(self, nums: List[int], k: int) -> int:
        from collections import defaultdict
        count = defaultdict(int)
        for i in range(len(nums) - k + 1):
            subarray = nums[i:i + k]
            unique_elements = set(subarray)
            for elem in unique_elements:
                count[elem] += 1
        candidates = [num for num, cnt in count.items() if cnt == 1]
        return max(candidates) if candidates else -1

class Solution:
    def permute(self, nums: List[int]) -> List[List[int]]:
        def backtrack(start=0):
            if start == len(nums):
                res.append(nums[:])
            for i in range(start, len(nums)):
                nums[start], nums[i] = nums[i], nums[start]
                backtrack(start + 1)
                nums[start], nums[i] = nums[i], nums[start]
        res = []
        backtrack()
        return res

class Solution:
    def minCost(self, nums: List[int]) -> int:
        n = len(nums)
        @functools.lru_cache(None)
        def dp(last: int, i: int) -> int:
            if i == n:  # Single element left.
                return nums[last]
            if i == n - 1:  # Two elements left.
                return max(nums[last], nums[i])
            a = max(nums[i], nums[i + 1]) + dp(last, i + 2)
            b = max(nums[last], nums[i]) + dp(i + 1, i + 2)
            c = max(nums[last], nums[i + 1]) + dp(i, i + 2)
            return min(a, b, c)
        return dp(0, 1)
